    "\u05de\u05ea\u05d7\u05d9\u05dc\u05d5\u05ea \u05d1\u05de\u05d5\u05e6\u05d0\u05d9 \u05e9\u05d1\u05ea \u05e9\u05dc\u05e4\u05e0\u05d9 \u05e8\u05d0\u05e9 \u05d4\u05e9\u05e0\u05d4 "
