    "\u05d1\u05de\u05d4\u05dc\u05da \u05d0\u05dc\u05d5\u05dc \u05dc\u05e4\u05e0\u05d9 \u05ea\u05d7\u05d9\u05dc\u05ea \u05d4\u05e1\u05dc\u05d9\u05d7\u05d5\u05ea:\n"
